using System;

namespace AvatarBuilder.Modules.Vision.Reconstruction.Warping;

internal static class DenseFaceWarpViewerPage
{
	private const string Template = "<!doctype html>\n<html lang=\"en\">\n<head>\n<meta charset=\"utf-8\">\n<meta name=\"viewport\" content=\"width=device-width,initial-scale=1\">\n<title>Dense Face Warp Proof</title>\n<style>\n:root{color-scheme:dark;background:#06111a;color:#e8f5ff;font:13px/1.4 Segoe UI,Arial,sans-serif}\n*{box-sizing:border-box}body{margin:0;min-height:100vh;background:#06111a}.toolbar{height:54px;display:flex;align-items:center;gap:8px;padding:8px 12px;border-bottom:1px solid #284052;background:#091722}.toolbar strong{font-size:16px;margin-right:10px}.toolbar button{height:34px;padding:0 12px;color:#dff3ff;background:#102638;border:1px solid #3876a0;border-radius:2px;cursor:pointer}.toolbar button.on{background:#176287;border-color:#63c9f5}.metrics{margin-left:auto;color:#9fdcf6;text-align:right}.views{height:calc(100vh - 104px);display:grid;grid-template-columns:1fr 1fr;gap:1px;background:#284052}.panel{position:relative;min-width:0;background:#050d14}.panel h2{position:absolute;z-index:2;top:12px;left:14px;margin:0;font-size:14px;color:#f2fbff}.panel p{position:absolute;z-index:2;top:34px;left:14px;margin:0;color:#8fb9d0}.panel canvas{width:100%;height:100%;display:block}.footer{height:50px;padding:7px 12px;border-top:1px solid #284052;color:#b9d7e7;display:flex;align-items:center;gap:22px}.good{color:#68e0a5}.warn{color:#ffd66e}@media(max-width:900px){.views{grid-template-columns:1fr;grid-template-rows:1fr 1fr}.metrics{display:none}.views{height:calc(100vh - 104px)}}\n</style>\n</head>\n<body>\n<div class=\"toolbar\">\n  <strong>Dense Face Warp Proof</strong>\n  <button id=\"mesh\" class=\"on\">Mesh</button>\n  <button id=\"points\">Points</button>\n  <button id=\"anchors\" class=\"on\">Measured Anchors</button>\n  <button id=\"rays\" class=\"on\">Displacement Rays</button>\n  <button id=\"reset\">Reset 3D View</button>\n  <div class=\"metrics\" id=\"metrics\"></div>\n</div>\n<main class=\"views\">\n  <section class=\"panel\"><h2>3DDFA-V2 Prior</h2><p>Single-image dense identity scaffold</p><canvas id=\"source\"></canvas></section>\n  <section class=\"panel\"><h2>MediaPipe-Constrained Result</h2><p>Same topology, pulled by directly observed multi-view evidence</p><canvas id=\"warped\"></canvas></section>\n</main>\n<footer class=\"footer\"><span id=\"status\"></span><span>Drag either view to rotate. Mouse wheel zooms both.</span></footer>\n<script>\nconst data=__WARP_DATA__;\nconst source=Float64Array.from(data.sourceCoordinates), warped=Float64Array.from(data.warpedCoordinates), edges=Int32Array.from(data.edgeIndices);\nconst canvases=[document.getElementById('source'),document.getElementById('warped')];\nconst state={yaw:-0.18,pitch:0.04,zoom:1,mesh:true,points:false,anchors:true,rays:true};\nconst fmt=n=>Number(n).toFixed(4);\ndocument.getElementById('metrics').innerHTML=`${data.sourceVertexCount.toLocaleString()} vertices | ${data.appliedControlPointCount} trusted controls<br>anchor RMS ${fmt(data.sourceAnchorRms)} &rarr; ${fmt(data.warpedAnchorRms)}<br>movement p50 ${fmt(data.medianAppliedDisplacement)} | p95 ${fmt(data.percentile95AppliedDisplacement)} | safety clamp ${fmt(data.safetyClampVertexPercent)}%`;\nconst improved=data.warpedAnchorRms<data.sourceAnchorRms;\ndocument.getElementById('status').innerHTML=`<span class=\"${improved?'good':'warn'}\">${data.status}</span>`;\nfunction toggle(id,key){const b=document.getElementById(id);b.onclick=()=>{state[key]=!state[key];b.classList.toggle('on',state[key]);drawAll()}}\ntoggle('mesh','mesh');toggle('points','points');toggle('anchors','anchors');toggle('rays','rays');\ndocument.getElementById('reset').onclick=()=>{state.yaw=-0.18;state.pitch=0.04;state.zoom=1;drawAll()};\nfunction rotate(x,y,z){const cy=Math.cos(state.yaw),sy=Math.sin(state.yaw),cp=Math.cos(state.pitch),sp=Math.sin(state.pitch);const x1=x*cy+z*sy,z1=-x*sy+z*cy;return [x1,y*cp-z1*sp,y*sp+z1*cp]}\nfunction bounds(coords){let m=0;for(let i=0;i<coords.length;i++)m=Math.max(m,Math.abs(coords[i]));return Math.max(m,1)}\nconst extent=Math.max(bounds(source),bounds(warped));\nfunction sizeCanvas(c){const d=Math.max(1,window.devicePixelRatio||1),r=c.getBoundingClientRect(),w=Math.max(1,Math.round(r.width*d)),h=Math.max(1,Math.round(r.height*d));if(c.width!==w||c.height!==h){c.width=w;c.height=h}return [w,h,d]}\nfunction project(v,w,h){const r=rotate(v[0],v[1],v[2]),s=Math.min(w,h)*0.39*state.zoom/extent;return [w/2+r[0]*s,h/2-r[1]*s,r[2]]}\nfunction draw(canvas,coords,isWarped){const ctx=canvas.getContext('2d'),[w,h,d]=sizeCanvas(canvas);ctx.clearRect(0,0,w,h);ctx.lineCap='round';ctx.lineJoin='round';const projected=new Array(coords.length/3);for(let i=0,p=0;i<coords.length;i+=3,p++)projected[p]=project([coords[i],coords[i+1],coords[i+2]],w,h);\n if(state.mesh){const edgeCount=edges.length/2,stride=Math.max(1,Math.ceil(edgeCount/32000));ctx.strokeStyle=isWarped?'rgba(72,225,203,.42)':'rgba(82,174,229,.30)';ctx.lineWidth=Math.max(0.65*d,0.7);ctx.beginPath();for(let e=0;e<edgeCount;e+=stride){const a=projected[edges[e*2]],b=projected[edges[e*2+1]];if(!a||!b)continue;ctx.moveTo(a[0],a[1]);ctx.lineTo(b[0],b[1])}ctx.stroke()}\n if(state.points){ctx.fillStyle=isWarped?'rgba(119,255,226,.58)':'rgba(136,211,255,.48)';for(let p=0;p<projected.length;p+=2){const v=projected[p];ctx.fillRect(v[0],v[1],Math.max(1,d),Math.max(1,d))}}\n if(state.rays&&isWarped){ctx.strokeStyle='rgba(255,203,92,.55)';ctx.lineWidth=Math.max(0.8*d,1);ctx.beginPath();for(const c of data.controls){const a=project(c.source,w,h),b=project(c.target,w,h);ctx.moveTo(a[0],a[1]);ctx.lineTo(b[0],b[1])}ctx.stroke()}\n if(state.anchors){for(const c of data.controls){const v=project(isWarped?c.target:c.source,w,h),alpha=.35+.65*c.confidence;ctx.fillStyle=`rgba(255,211,105,${alpha})`;ctx.beginPath();ctx.arc(v[0],v[1],Math.max(1.8*d,2),0,Math.PI*2);ctx.fill()}}\n}\nfunction drawAll(){draw(canvases[0],source,false);draw(canvases[1],warped,true)}\nfor(const canvas of canvases){let drag=false,lastX=0,lastY=0;canvas.addEventListener('pointerdown',e=>{drag=true;lastX=e.clientX;lastY=e.clientY;canvas.setPointerCapture(e.pointerId)});canvas.addEventListener('pointermove',e=>{if(!drag)return;state.yaw+=(e.clientX-lastX)*.009;state.pitch=Math.max(-1.45,Math.min(1.45,state.pitch+(e.clientY-lastY)*.009));lastX=e.clientX;lastY=e.clientY;drawAll()});canvas.addEventListener('pointerup',()=>drag=false);canvas.addEventListener('wheel',e=>{e.preventDefault();state.zoom=Math.max(.35,Math.min(5,state.zoom*(e.deltaY<0?1.1:.9)));drawAll()},{passive:false})}\nwindow.addEventListener('resize',drawAll);drawAll();\n</script>\n</body>\n</html>";

	public static string Build(string documentJson)
	{
